│   ├── core/                  # The "Brain": ReAct engine & state management
│   │   ├── chatManager.js    # Message queue & session orchestration
│   │   ├── turnProcessor.js   # Main ReAct loop & turn logic
│   │   ├── ApiCommunicator.js # Resilient API communication layer
